const all = $input.all().map(i => i.json);

const cvs = all.filter(i => i.YCODCV_0);       
const responsables = all.filter(i => i.XEMAIL_0);

if (cvs.length === 0 || responsables.length === 0) {
  return [];
}

// Group CVs par poste
const cvsByPoste = {};
cvs.forEach(cv => {
  const poste = cv.YTIT_0 || 'Poste non défini';
  if (!cvsByPoste[poste]) cvsByPoste[poste] = [];
  cvsByPoste[poste].push(cv);
});

// Email pour tout les responsable
const emails = [];

responsables.forEach(respo => {

let text = `Bonjour ${respo.XNAMSAL_0 || ''} ${respo.XPRENOM_0 || ''},\n\n`;
  text += `Nous vous informons qu’un ensemble de CV a été saisi sur Sage X3 au cours de la journée d’hier.\n\n`;
  text += `Vous trouverez ci-dessous la liste des candidatures reçues, classées par poste :\n\n`;

  for (const poste in cvsByPoste) {
    text += `📌 POSTE : ${poste}\n`;

    cvsByPoste[poste].forEach((cv, index) => {
      text += `${index + 1}. Code CV : ${cv.YCODCV_0}
Nom & Prénom : ${cv.YNOM_0} ${cv.YPRENOM_0}
Email candidat : ${cv.YEMAILPER_0 || 'Non renseigné'}\n\n`;
    });
  }

  text += `Cordialement,\nService Si`;

  emails.push({
    json: {
      email: {
        to: respo.XEMAIL_0,
        subject: `📄 Nouveaux CVs reçus`,
        text
      }
    }
  });
});

return emails;
